export const OUTROS: SoilClass = {
  code: "OUTROS",
  label: "Outros / não catalogado",
  color: "#9e9e9e",
  description:
    "Polígonos cujo código de simbologia (COD_SIMBOL) não corresponde a nenhuma classe catalogada neste mapa. Inclui unidades raras, combinações específicas ou notação fora do padrão dos prefixos do SiBCS.",
};

const CODE_INDEX = new Map(SOIL_CLASSES.map((c) => [c.code, c]));

/** Retorna o registro do catálogo para o código fornecido (ou "Outros"). */
export function getSoilClass(code: string | null | undefined): SoilClass {
  if (!code) return OUTROS;
  return CODE_INDEX.get(code) ?? OUTROS;
}

/** Extrai as letras iniciais de COD_SIMBOL e mapeia para um código do catálogo. */
export function classifyCodSimbol(codSimbol: string | null | undefined): string {
  if (!codSimbol) return OUTROS.code;
  const match = codSimbol.match(/^[A-Za-z]+/);
  if (!match) return OUTROS.code;
  return CODE_INDEX.has(match[0]) ? match[0] : OUTROS.code;
}
